SELECT ?actress ?actressLabel WHERE {
  ?actress wdt:P166 wd:Q29191127;
          wdt:P21 wd:Q6581097.
  ?actress p:P166 ?awardStatement.
  ?awardStatement ps:P166 wd:Q29191127.
  ?awardStatement pq:P585 ?awardDate.
  FILTER NOT EXISTS {
    ?actress p:P25 ?spouseStatement.
    ?spouseStatement pq:P585 ?spouseDate.
    FILTER(?spouseDate <= ?awardDate)
  }
  ?actress rdfs:label ?actressLabel.
  FILTER(LANG(?actressLabel) = 'en')
}

